const nodemailer = require('nodemailer');
const fs = require('fs');
const crypto = require('crypto');

// Load DKIM private key from secure storage (e.g., Azure Key Vault)
const dkimPrivateKey = fs.readFileSync('/var/secrets/dkim-private.pem', 'utf8');

// Configure SMTP transport with DKIM signing
const transporter = nodemailer.createTransport({
  host: 'smtp.example.com',
  port: 587,
  secure: false,
  auth: {
    user: process.env.SMTP_USER,
    pass: process.env.SMTP_PASS
  },
  dkim: {
    domainName: 'example.com',
    keySelector: 'default',
    privateKey: dkimPrivateKey,
    cacheDir: false, // Prevent signature caching to mitigate replay attacks
    cacheTreshold: 0,
    headerFieldNames: 'from:to:subject:date:message-id' // Include Date for freshness
  }
});

// Send email with DKIM signature
async function sendSecureEmail(to, subject, htmlBody) {
  const messageId = `<${crypto.randomUUID()}@example.com>`;

  const mailOptions = {
    from: 'noreply@example.com',
    to: to,
    subject: subject,
    html: htmlBody,
    messageId: messageId, // Unique Message-ID prevents replay
    date: new Date() // Explicit timestamp for replay detection
  };

  try {
    const info = await transporter.sendMail(mailOptions);
    console.log('Email sent with DKIM signature:', info.messageId);
    console.log('DKIM-Signature header:', info.accepted);
    return info;
  } catch (error) {
    console.error('DKIM signing failed:', error);
    throw error;
  }
}

// Example usage
sendSecureEmail(
  'user@recipient.com',
  'Financial Report Q4 2025',
  '<p>Please review the attached quarterly report.</p>'
);

// Recipient-side DKIM verification (for email gateways)
const dkimVerify = require('dkim-verify');

function verifyDKIMSignature(rawEmail) {
  dkimVerify.verify(rawEmail, (err, result) => {
    if (err) {
      console.error('DKIM verification failed:', err);
      return false;
    }

    // Check signature age to prevent replay attacks
    const signatureDate = new Date(result.signatureHeader.t);
    const currentDate = new Date();
    const ageInHours = (currentDate - signatureDate) / (1000 * 60 * 60);

    if (ageInHours > 24) {
      console.warn('DKIM signature older than 24 hours - possible replay attack');
      return false;
    }

    console.log('DKIM verification passed:', result.verified);
    return result.verified;
  });
}
